import React from 'react';
import { formatMoneyVnd } from '@linm-soft-org/linm-web-common-components';
import type { InvoicePaymentLineDto } from '../../services/bh/models';
import df from '../../styles/documentForm.module.css';

export type InvoicePaymentSectionProps = {
  testIdPrefix: string;
  payments: InvoicePaymentLineDto[];
  viewSectionClass?: string;
};

export const InvoicePaymentSection: React.FC<InvoicePaymentSectionProps> = ({
  testIdPrefix,
  payments,
  viewSectionClass,
}) => {
  if (payments.length === 0) return null;

  return (
    <div
      className={[df.section, viewSectionClass].filter(Boolean).join(' ')}
      data-testid={`${testIdPrefix}-payment-section`}
    >
      <h2 className={df.sectionTitle}>Hình thức thanh toán</h2>
      <div className={df.tableWrapper}>
        <table className={df.linesTable}>
          <thead>
            <tr>
              <th>Kênh TT</th>
              <th>Mã kênh</th>
              <th>Số tiền</th>
              <th>Phiếu thu</th>
            </tr>
          </thead>
          <tbody>
            {payments.map((p, idx) => (
              <tr key={`${p.receiptId}-${idx}`} data-testid={`${testIdPrefix}-payment-row-${idx}`}>
                <td>{p.paymentChannelName ?? '—'}</td>
                <td>{p.paymentChannelCode ?? '—'}</td>
                <td style={{ textAlign: 'right' }}>{formatMoneyVnd(p.amount)}</td>
                <td>{p.receiptCode}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
